import { name as packageName, version } from '../package.json';
import type {
  BeforeSend,
  InjectSpeedInsightsProps,
  SpeedInsightsProps,
} from './types';

export function isBrowser(): boolean {
  return typeof window !== 'undefined';
}

function detectEnvironment(): 'development' | 'production' {
  try {
    const env = process.env.NODE_ENV;
    if (env === 'development' || env === 'test') {
      return 'development';
    }
  } catch {
    // do nothing, this is okay
  }
  return 'production';
}

export function isProduction(): boolean {
  return detectEnvironment() === 'production';
}

export function isDevelopment(): boolean {
  return detectEnvironment() === 'development';
}

export function computeRoute(
  pathname: string | null,
  pathParams: Record<string, string | string[]> | null,
): string | null {
  if (!pathname || !pathParams) {
    return pathname;
  }

  let result = pathname;
  try {
    const entries = Object.entries(pathParams);
    // simple keys must be handled first
    for (const [key, value] of entries) {
      if (!Array.isArray(value)) {
        const matcher = turnValueToRegExp(value);
        if (matcher.test(result)) {
          result = result.replace(matcher, `/[${key}]`);
        }
      }
    }
    // array values next
    for (const [key, value] of entries) {
      if (Array.isArray(value)) {
        const matcher = turnValueToRegExp(value.join('/'));
        if (matcher.test(result)) {
          result = result.replace(matcher, `/[...${key}]`);
        }
      }
    }
    return result;
  } catch {
    return pathname;
  }
}

function turnValueToRegExp(value: string): RegExp {
  return new RegExp(`/${escapeRegExp(value)}(?=[/?#]|$)`);
}

function escapeRegExp(string: string): string {
  return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function getScriptSrc(
  props: SpeedInsightsProps & { basePath?: string },
): string {
  if (props.scriptSrc) {
    return makeAbsolute(props.scriptSrc);
  }
  if (isDevelopment()) {
    return 'https://va.vercel-scripts.com/v1/speed-insights/script.debug.js';
  }
  if (props.dsn) {
    return 'https://va.vercel-scripts.com/v1/speed-insights/script.js';
  }
  if (props.basePath) {
    return makeAbsolute(`${props.basePath}/speed-insights/script.js`);
  }
  return '/_vercel/speed-insights/script.js';
}

export function loadProps(
  explicitProps: InjectSpeedInsightsProps,
  confString?: string,
): {
  src: string;
  beforeSend?: BeforeSend;
  dataset: Record<string, string>;
} {
  let props = explicitProps;
  if (confString) {
    try {
      props = {
        ...(JSON.parse(confString)
          ?.speedInsights as Partial<SpeedInsightsProps>),
        ...explicitProps,
      };
    } catch {
      // Invalid JSON, use only explicit props
    }
  }

  const dataset: Record<string, string> = {
    sdkn: packageName + (props.framework ? `/${props.framework}` : ''),
    sdkv: version,
  };

  if (props.sampleRate) {
    dataset.sampleRate = props.sampleRate.toString();
  }
  if (props.route) {
    dataset.route = props.route;
  }
  if (isDevelopment() && props.debug === false) {
    dataset.debug = 'false';
  }
  if (props.dsn) {
    dataset.dsn = props.dsn;
  }

  if (props.endpoint) {
    dataset.endpoint = makeAbsolute(props.endpoint);
  } else if (props.basePath) {
    // backward compatibility
    dataset.endpoint = makeAbsolute(`${props.basePath}/speed-insights/vitals`);
  }

  return {
    src: getScriptSrc(props),
    beforeSend: props.beforeSend,
    dataset,
  };
}

function makeAbsolute(url: string): string {
  return url.startsWith('http://') ||
    url.startsWith('https://') ||
    url.startsWith('/')
    ? url
    : `/${url}`;
}
import { initQueue } from './queue';
import type {
  BeforeSend,
  InjectSpeedInsightsProps,
  SpeedInsightsProps,
} from './types';
import { computeRoute, isBrowser, loadProps } from './utils';

/**
 * Injects the Vercel Speed Insights script into the page head and starts tracking page views. Read more in our [documentation](https://vercel.com/docs/speed-insights).
 * @param [props] - Speed Insights options.
 * @param [props.debug] - Whether to enable debug logging in development. Defaults to `true`.
 * @param [props.beforeSend] - A middleware function to modify events before they are sent. Should return the event object or `null` to cancel the event.
 * @param [props.sampleRate] - When setting to 0.5, 50% of the events will be sent to Vercel Speed Insights. Defaults to `1`.
 * @param [props.route] - The dynamic route of the page.
 * @param [props.dsn] - The DSN of the project to send events to. Only required when self-hosting.
 * @param [confString] - an optional JSON string (InjectSpeedInsightsProps) containing the default configuration. Explicit props will take over any provided default.
 */
function injectSpeedInsights(
  props: InjectSpeedInsightsProps = {},
  confString?: string,
): {
  setRoute: (route: string | null) => void;
} | null {
  // When route is null, it means that pages router is not ready yet. Will resolve soon
  if (!isBrowser() || props.route === null) return null;

  initQueue();

  const { beforeSend, src, dataset } = loadProps(props, confString);

  if (document.head.querySelector(`script[src*="${src}"]`)) return null;

  if (beforeSend) {
    window.si?.('beforeSend', beforeSend);
  }

  const script = document.createElement('script');
  script.src = src;
  script.defer = true;

  // Apply all dataset attributes from loadProps
  for (const [key, value] of Object.entries(dataset)) {
    script.dataset[key] = value;
  }

  script.onerror = (): void => {
    console.log(
      `[Vercel Speed Insights] Failed to load script from ${src}. Please check if any content blockers are enabled and try again.`,
    );
  };

  document.head.appendChild(script);

  return {
    setRoute: (route: string | null): void => {
      script.dataset.route = route ?? undefined;
    },
  };
}

export { injectSpeedInsights, computeRoute };
export type { SpeedInsightsProps, BeforeSend as BeforeSendMiddleware };

export default {
  injectSpeedInsights,
  computeRoute,
};
// !! important !!
// do not access env variables using process.env[varname]
// some bundlers won't replace the value at build time.

export function getBasePath(): string | undefined {
  if (typeof process === 'undefined' || typeof process.env === 'undefined') {
    return undefined;
  }
  return process.env.REACT_APP_VERCEL_OBSERVABILITY_BASEPATH;
}

export function getConfigString(): string | undefined {
  if (typeof process === 'undefined' || typeof process.env === 'undefined') {
    return undefined;
  }
  return process.env.REACT_APP_VERCEL_OBSERVABILITY_CLIENT_CONFIG;
}
